import React, { useEffect, useState } from "react";
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer
} from "recharts";

function App() {
  const [leftFootData, setLeftFootData] = useState([]);

  useEffect(() => {
    fetch("http://localhost:8000/data") // change to backend URL
      .then((res) => res.json())
      .then((data) => {
        setLeftFootData(data.leftFoot || []);
      });
  }, []);

  return (
    <div style={{ padding: "20px" }}>
      <h2>Left Foot Acceleration - Raw</h2>
      <ResponsiveContainer width="100%" height={300}>
        <LineChart data={leftFootData}>
          <CartesianGrid stroke="#ccc" />
          <XAxis dataKey="timestamp" />
          <YAxis />
          <Tooltip />
          <Legend />
          <Line type="monotone" dataKey="raw.x" stroke="#ff4d4f" name="Accel X" dot={false} />
          <Line type="monotone" dataKey="raw.y" stroke="#52c41a" name="Accel Y" dot={false} />
          <Line type="monotone" dataKey="raw.z" stroke="#1890ff" name="Accel Z" dot={false} />
        </LineChart>
      </ResponsiveContainer>

      <h2>Left Foot Acceleration - DC Bias Removed</h2>
      <ResponsiveContainer width="100%" height={300}>
        <LineChart data={leftFootData}>
          <CartesianGrid stroke="#ccc" />
          <XAxis dataKey="timestamp" />
          <YAxis />
          <Tooltip />
          <Legend />
          <Line type="monotone" dataKey="dcb_removed.x" stroke="#ff4d4f" name="Accel X (DCB)" dot={false} />
          <Line type="monotone" dataKey="dcb_removed.y" stroke="#52c41a" name="Accel Y (DCB)" dot={false} />
          <Line type="monotone" dataKey="dcb_removed.z" stroke="#1890ff" name="Accel Z (DCB)" dot={false} />
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
}

export default App;
